#include "kernel.h"
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <mma.h>

// Use wmma namespace for Ampere architecture
using namespace nvcuda::wmma;

// Problem Constants
constexpr int N_CONST = 5120;
constexpr int K_CONST = 2048;

// Tile Dimensions
// Block Size: 1024 threads (32 warps)
// Each warp computes one 16x16 tile of C
// 32 warps -> 8 rows of tiles x 4 cols of tiles -> 128x64 C tile
constexpr int BLOCK_M = 128;
constexpr int BLOCK_N = 64;
constexpr int BLOCK_K = 16;
constexpr int BLOCK_SIZE = 1024;

// Shared Memory
// A: [BLOCK_M][BLOCK_K] -> 128x16 halfs
// B: [BLOCK_K][BLOCK_N] -> 16x64 halfs
// C: [BLOCK_M][BLOCK_N] -> 128x64 floats
__shared__ half shared_A[BLOCK_M][BLOCK_K];
__shared__ half shared_B[BLOCK_K][BLOCK_N];
__shared__ float shared_C[BLOCK_M][BLOCK_N];

// Fragment types - layout is encoded in the type definition
// 6 template parameters: type, m, n, k, data_type, layout
typedef fragment<matrix_a, 16, 16, 16, half, row_major> FragmentA;
typedef fragment<matrix_b, 16, 16, 16, half, row_major> FragmentB;
typedef fragment<accumulator, 16, 16, 16, float, void> FragmentC;

__global__ void gemm_kernel(half* A, half* B, half* C, int M, int N, int K) {
    int tid = threadIdx.x;
    int bx = blockIdx.x;
    int by = blockIdx.y;

    int m_start = bx * BLOCK_M;
    int n_start = by * BLOCK_N;

    int warp_id = tid / 32;
    int lane_id = tid % 32;

    // Map warp to C tile position (16x16 tiles)
    // 32 warps -> 8 rows (0..7) x 4 cols (0..3)
    int warp_row = warp_id / 4; 
    int warp_col = warp_id % 4;

    int c_row_start = warp_row * 16;
    int c_col_start = warp_col * 16;

    FragmentC frag_C;
    fill_fragment(frag_C, 0.0f);

    for (int k = 0; k < K_CONST; k += BLOCK_K) {
        // Load A into shared memory
        // shared_A: [BLOCK_M][BLOCK_K]
        // 1024 threads load 128x16 elements (2048 elements)
        // Each thread loads 2 elements
        int a_row = tid / 16;
        int a_col = tid % 16;

        if (a_row < BLOCK_M && a_col < BLOCK_K) {
            int global_row = m_start + a_row;
            int global_col = k + a_col;
            if (global_row < M && global_col < K_CONST) {
                shared_A[a_row][a_col] = A[global_row * K_CONST + global_col];
            } else {
                shared_A[a_row][a_col] = __float2half(0.0f);
            }
        }
        __syncthreads();

        // Load B into shared memory
        // shared_B: [BLOCK_K][BLOCK_N]
        // 1024 threads load 16x64 elements (1024 elements)
        // Each thread loads 1 element
        int b_row = tid / 64;
        int b_col = tid % 64;

        if (b_row < BLOCK_K && b_col < BLOCK_N) {
            int global_col = n_start + b_col; // B is [N, K], so col index is N dim
            int global_row = k + b_row;       // row index is K dim
            if (global_col < N_CONST && global_row < K_CONST) {
                shared_B[b_row][b_col] = B[global_col * K_CONST + global_row];
            } else {
                shared_B[b_row][b_col] = __float2half(0.0f);
            }
        }
        __syncthreads();

        // wmma load and compute
        FragmentA frag_A;
        FragmentB frag_B;

        // Pointers to the specific 16x16 tile for this warp
        // A: [BLOCK_M][BLOCK_K]. Tile at [c_row_start][0]
        half* a_ptr = &shared_A[c_row_start][0];

        // B: [BLOCK_K][BLOCK_N]. Tile at [0][c_col_start]
        half* b_ptr = &shared_B[0][c_col_start];

        // load_matrix_sync for matrix_a/matrix_b takes 3 params:
        // (fragment, pointer, leading_dimension) - layout is in fragment type
        load_matrix_sync(frag_A, a_ptr, BLOCK_K);
        load_matrix_sync(frag_B, b_ptr, BLOCK_N);

        mma_sync(frag_C, frag_A, frag_B, frag_C);
    }

    // Store frag_C to shared_C
    // shared_C: [BLOCK_M][BLOCK_N]. Tile at [c_row_start][c_col_start]
    float* c_ptr = &shared_C[c_row_start][c_col_start];

    // store_matrix_sync for accumulator takes 4 params in order:
    // (fragment, pointer, leading_dimension, layout)
    // Use wmma::row_major to properly qualify the layout type
    store_matrix_sync(frag_C, c_ptr, BLOCK_N, wmma::row_major);

    __syncthreads();

    // Copy shared_C to Global C
    // shared_C is 128x64 floats (8192 elements)
    // 1024 threads. 8 elements per thread.
    for (int i = 0; i < 8; ++i) {
        int idx = tid + i * 1024;
        int r = idx / BLOCK_N;
        int c = idx % BLOCK_N;

        if (r < BLOCK_M && c < BLOCK_N) {
            int global_r = m_start + r;
            int global_c = n_start + c;
            if (global_r < M && global_c < N_CONST) {
                C[global_r * N_CONST + global_c] = __float2half(shared_C[r][c]);
            }
        }
    }
}

void launch_gemm_n5120_k2048(half* A, half* B, half* C, int M, int N, int K) {
    dim3 block(BLOCK_SIZE, 1, 1);
    dim3 grid((M + BLOCK_M - 1) / BLOCK_M, (N + BLOCK_N - 1) / BLOCK_N);

    gemm_kernel<<<grid, block>>>(A, B, C, M, N, K);

    // Error check
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        // In production, handle error appropriately
    }
}

#include <torch/extension.h>
#include <cuda_runtime.h>
#include "kernel.h"

#ifndef TORCH_EXTENSION_NAME
#define TORCH_EXTENSION_NAME gemm_n5120_k2048
#endif

/**
 * Host function to execute the GEMM kernel.
 * 
 * @param A Input tensor A [M, K] (FLOAT16, CUDA)
 * @param B Input tensor B [N, K] (FLOAT16, CUDA)
 * @return Output tensor C [M, N] (FLOAT16, CUDA)
 */
torch::Tensor run(torch::Tensor A, torch::Tensor B) {
    // Validate Device
    TORCH_CHECK(A.device().is_cuda(), "Input A must be on CUDA device");
    TORCH_CHECK(B.device().is_cuda(), "Input B must be on CUDA device");

    // Validate Dtype
    TORCH_CHECK(A.dtype() == torch::kHalf, "Input A must be of type FLOAT16");
    TORCH_CHECK(B.dtype() == torch::kHalf, "Input B must be of type FLOAT16");

    // Validate Shapes
    TORCH_CHECK(A.dim() == 2, "Input A must be 2D");
    TORCH_CHECK(B.dim() == 2, "Input B must be 2D");

    int M = A.size(0);
    int K = A.size(1);
    int N = B.size(0);

    TORCH_CHECK(K == 2048, "Dimension K must be 2048");
    TORCH_CHECK(N == 5120, "Dimension N must be 5120");

    // Allocate Output Tensor
    torch::Tensor C = torch::empty({M, N}, A.options());

    // Get raw pointers
    half* A_ptr = static_cast<half*>(A.data_ptr());
    half* B_ptr = static_cast<half*>(B.data_ptr());
    half* C_ptr = static_cast<half*>(C.data_ptr());

    // Launch Kernel
    launch_gemm_n5120_k2048(A_ptr, B_ptr, C_ptr, M, N, K);

    // Synchronize to ensure completion and check for errors
    cudaDeviceSynchronize();
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(cudaGetErrorString(err));
    }

    return C;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "Executes optimized GEMM kernel for N=5120, K=2048");
}
